mapper.select:
SELECT stpp.* FROM store_promotion_project stpp LEFT JOIN store_promotion_project_detail sppd ON stpp.id = sppd.project_id WHERE 1=1
AND stpp.name LIKE CONCAT('%', #{storePromotionProjectModel.name}, '%')
AND stpp.prom_id = #{storePromotionProjectModel.promId}
AND sppd.account = #{storePromotionProjectModel.account}
AND sppd.platform_type = #{storePromotionProjectModel.platformType}
GROUP BY stpp.id
